1	const BASE_PREMIUMS: Record<string, number> = {
2	  sword: 100,
3	  amulet: 60,
4	  staff: 80,
5	  potion: 40,
6	};
7	
8	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
9	const PROCESSING_FEE = 5;
10	
11	const premiumForItem = (item: { type: string }): number => {
12	  const base = BASE_PREMIUMS[item.type];
13	  return base + base * FIRST_INSURANCE_SURCHARGE_RATE;
14	};
15	
16	export const runScenario = (scenario: any): unknown => {
17	  const items = scenario.steps[0].items;
18	  const itemsTotal = items.reduce(
19	    (sum: number, item: any) => sum + premiumForItem(item),
20	    0,
21	  );
22	  const premium = itemsTotal + PROCESSING_FEE;
23	  return { results: [{ premium }] };
24	};
